149	{
150	    const double tune_freq = ZBX_FREQ_RANGE.clip(_desired_frequency);
151	    _tune_settings         = _get_tune_settings(tune_freq, _tune_table.get());
152	
153	    // Set mixer values so the backend expert knows how to calculate final frequency
154	    _lo1_inj_side = _tune_settings.lo1_inj_side;
155	    _lo2_inj_side = _tune_settings.lo2_inj_side;
156	
157	    _is_highband = _is_band_highband(_tune_settings);
158	    _lo1_enabled = !_is_highband.get();
159	
160	    double if1_freq      = tune_freq;
161	    const double lo_step = _lo_freq_range.step();
162	    // If we need to apply an offset to avoid injection locking, we need to
163	    // offset in different directions for different channels on the same zbx
164	    const double lo_offset_sign = (_chan == 0) ? -1 : 1;
165	    // In high band, LO1 is not needed (the signal is already at a high enough
166	    // frequency for the second stage)
167	    if (_lo1_enabled) {
168	        // Calculate the ideal IF1:
169	        if1_freq = _calc_if1_freq(tune_freq, _tune_settings);
170	        // We calculate the LO1 frequency by first shifting the tune frequency to the
171	        // desired IF, and then applying an offset such that CH0 and CH1 tune to distinct
172	        // LO1 frequencies: This is done to prevent the LO's from interfering with each
173	        // other in a phenomenon known as injection locking.
174	        const double lo1_freq =
175	            if1_freq - (static_cast<double>(_tune_settings.lo1_inj_side) * tune_freq)
176	            + (lo_offset_sign * lo_step);
177	        // Now, quantize the LO frequency to the nearest valid value:
178	        _desired_lo1_frequency = _lo_freq_range.clip(lo1_freq, true);
179	        // Because LO1 frequency probably changed during quantization, we simply
180	        // re-calculate the now-valid IF1 (the following equation is the same as
181	        // the LO1 frequency calculation, but solved for if1_freq):
182	        if1_freq = _desired_lo1_frequency
183	                   + static_cast<double>(_tune_settings.lo1_inj_side) * tune_freq;
184	    }
185	
186	    _lo2_enabled = true;
187	    // Calculate ideal IF2 frequency:
188	    const double if2_freq = _calc_ideal_if2_freq(tune_freq, _tune_settings);
189	    // Calculate LO2 frequency from that:
190	    _desired_lo2_frequency = _calc_lo2_freq(if1_freq, if2_freq, _lo2_inj_side);
191	    // Similar to LO1, apply an offset such that CH0 and CH1 tune to distinct LO2
192	    // frequencies to prevent potential interference between CH0 and CH1 LO2's from
193	    // injection locking: In highband (LO1 disabled), this must explicitly be done below.
194	    // In lowband (LO1 enabled), the LO1 will have already been shifted and, as a result,
195	    // the LO2's will have already been shifted to compensate for LO1 in previous
196	    // function. Note that in lowband, the LO1's and LO2's will be offset between CH0 and
197	    // CH1; however, they will be offset in opposite direction such that the NCO frequency
198	    // will be the same between CH0 and CH1. This is not the case for highband (only LO2
199	    // and they must be offset).
200	    if (!_lo1_enabled) {
201	        _desired_lo2_frequency = _desired_lo2_frequency + (lo_offset_sign * lo_step);
